# coding: utf-8
import json
from datetime import date, datetime
from typing import Dict, List, Union

from rainbow_admin.errors import RainbowException
from rainbow_admin.group import BaseGroup
from rainbow_admin.template import Template
from rainbow_admin.utils import cached_property, logger


def rainbow_value2python_value(value, value_type):
    """自动根据value_type，转换为python类型"""
    try:
        if isinstance(value, str) and value_type == 4:
            try:
                return json.loads(value)
            except json.JSONDecodeError as e:
                logger.warning(f"load json value fail: {e}\nvalue={value}")
        elif isinstance(value, str) and value_type == 1:
            if value.isdigit():
                return int(value)
            else:
                return float(value)
        elif isinstance(value, str) and value_type == 18:
            return datetime.strptime(value, "%Y-%m-%d").date()
    except Exception as e:
        logger.warning(
            f"convert value '{value}' to type "
            f"{KeyValue.VALUE_TYPE_MAP.get(value_type, 'UNKNOWN')} fail: {e}"
        )
    return value


def guess_value_type(value):
    """没有指定value_type时，需要猜测 value_type"""
    if isinstance(value, (int, float)):
        return str(value), 1
    elif isinstance(value, str):
        if value.find("\n") == -1:
            return value, 2
        else:
            return value, 3
    elif isinstance(value, (dict, list)):
        # json
        return json.dumps(value, ensure_ascii=False, indent=4), 4
    elif isinstance(value, (date, datetime)):
        return str(value), 18
    return str(value), 2


class KeyValue(object):
    VALUE_TYPE_MAP = {
        0: "NONE",
        1: "NUMBER",
        2: "STRING",
        3: "TEXT",
        4: "JSON",
        6: "File",
        5: "XML",
        18: "DATE",
        20: "YAML",
    }

    def __init__(
        self,
        key,
        value,
        value_type=0,
        description="",
        group: "KVGroup" = None,
        **kwargs,
    ):
        self.key = key
        self.value_type = value_type
        self.description = description
        # 从rainbow拉取时的原始值
        self.origin_value = value
        # 根据类型自动转换的python值
        self.value = rainbow_value2python_value(value, value_type)

        self.group = group
        self.admin = group.admin if group else None

        self.status = kwargs.get("status")
        self.from_group_id = kwargs.get("from_group_id") or self.group.group_id

        self.infos = kwargs

    def attach_group(self, group):
        self.group = group

    @property
    def create_time(self):
        return self.infos.get("create_time")

    @property
    def operator(self):
        return self.infos.get("operator")

    @property
    def check_rule(self):
        return self.infos.get("check_rule")

    @property
    def is_public_config(self) -> bool:
        return self.group.group_id != self.from_group_id

    @property
    def public_group(self) -> "BaseGroup":
        if self.is_public_config:
            return self.admin.get_group_by_id(self.from_group_id)

    def convert2private(self):
        """关联的公共配置，转为私有"""
        if not self.is_public_config:
            raise RainbowException("this config is not related to public group")
        self.from_group_id = self.group.group_id
        self.group.update_config([self])
        self.group.clear_cache()

    @cached_property
    def id(self):
        return self.infos.get("id")

    def save(self):
        if not self.group:
            raise RainbowException("此KeyValue没有指定所关联的group")
        # 2022.11服务端调整规则，kv不返回key对应的id值了
        if self.id is not None:
            self.group.update_config([self])
        else:
            self.group.add_config([self])

    def delete(self):
        # 2022.11服务端调整规则，kv不返回key对应的id值了
        if self.id is not None:
            self.group.delete_config(self)

    def to_api_value(self, op_type=None):
        """调用api时，要将本结构体转换为api指定格式的dict"""
        if self.value_type == 0:
            self.value, self.value_type = guess_value_type(self.value)
        if self.value_type == 4 and isinstance(self.value, (dict, list)):
            # when is json and is update, need convert
            self.value = json.dumps(self.value, ensure_ascii=False, indent=4)
        d = dict(
            id=self.id,
            key=self.key,
            value=str(self.value),
            value_type=self.value_type,
            description=self.description,
            group_id=self.group.group_id,
            from_group_id=self.from_group_id,
        )
        if op_type:
            if op_type == "add":
                d["config_op_type"] = 2
            elif op_type == "delete":
                d["config_op_type"] = 3
            elif op_type == "update":
                d["config_op_type"] = 1
        return d

    def __str__(self) -> str:
        return f"{self.__class__.__name__}({self.key}={self.value})"

    __repr__ = __str__

    def clone(self):
        cloned = self.__class__(
            self.key,
            self.value,
            self.value_type,
            self.description,
            self.group,
            **self.infos,
        )
        return cloned


class FileDeployInfo(object):
    def __init__(
        self,
        path: str,
        before_shell: str = "",
        after_shell: str = "",
        client_shell: str = "",
        client_switch: bool = False,
        executor: str = None,
        **kwargs
    ):
        """
        :param path: 文件下载临时目录
        :param before_shell: 前置命令
        :param after_shell: 后置命令
        :param client_shell: 抓取客户端标识的 shell 语句
        :param client_switch: 是否开启抓取客户端标识
        :param executor: """
        self.path = path
        self.after_shell = after_shell
        self.before_shell = before_shell
        self.client_shell = client_shell
        self.client_switch = client_switch
        self.executor = executor

    def __str__(self) -> str:
        return f"{self.__class__.__name__}(path={self.path}, before_shell={self.before_shell}, after_shell={self.after_shell}, client_shell={self.client_shell}, client_switch={self.client_switch}, executor={self.executor})"


class KVGroup(BaseGroup):
    CONFIG_TYPE = 0

    def get_info(self, version_id=0, version_name=None):
        """
        :param version_id: 0为当前配置
        :param version_name: None 为当前配置
        :return:
        """
        if version_name:
            l = list(
                filter(lambda x: x['version_name'] == version_name, self.history_versions)
            )
            if len(l) == 0:
                raise RainbowException("历史版本中查不到指定的版本名 {verison_name}")
            if version_id and version_id != l[0]['version_id']:
                raise RainbowException("同时指定了version_id和version_name，但根据name查询到的id不一致 {verison_name}")
            version_id = l[0]['version_id']
        return self.admin.api.query_group_config_info(
            self.group_id, self.group_name, version_id
        )

    def get_configs(self, version_id=0, version_name=None) -> List[KeyValue]:
        """k-v型表的 配置项实例化"""
        if version_name:
            l = list(
                filter(lambda x: x['version_name'] == version_name, self.history_versions)
            )
            if len(l) == 0:
                raise RainbowException("历史版本中查不到指定的版本名 {verison_name}")
            if version_id and version_id != l[0]['version_id']:
                raise RainbowException("同时指定了version_id和version_name，但根据name查询到的id不一致 {verison_name}")
            version_id = l[0]['version_id']
        return [
            KeyValue(**i, group=self)
            for i in self.get_info(version_id=version_id)["key_values"]
        ]

    def sync_from_public(self, public_group: "KVGroup", overwrite=False):
        """sdk自己实现公共分组同步，与页面上的同步可能会有差异，如果不满足需求可以自己实现。

        :param public_group: 公共分组
        :param overwrite: 会覆盖其他公共配置"""
        assert not self.is_public
        assert public_group.is_public
        versions = public_group.history_versions
        assert versions
        latest_version_id = versions[0]["version_id"]
        public_now_config = public_group.get_configs(latest_version_id)
        public_config_keys = {i.key for i in public_now_config}
        private_now_public_config = {
            k: v
            for k, v in self.configs.items()
            if v.from_group_id == public_group.group_id
        }
        will_add = []
        will_delete = []
        will_update = []
        for kv in public_now_config:
            if kv.key in self.configs:
                private_kv = self.configs[kv.key]
                # 有修改且是公共key
                if (
                    kv.origin_value != private_kv.origin_value
                    and private_kv.is_public_config
                ):
                    new_kv = kv.clone()
                    new_kv.group = self
                    new_kv.from_group_id = public_group.group_id
                    # 是要同步的公共分组，或者是要覆盖其他公共分组
                    if private_kv.from_group_id == public_group.group_id or overwrite:
                        will_update.append(new_kv)
            else:
                new_kv = kv.clone()
                new_kv.group = self
                new_kv.from_group_id = public_group.group_id
                will_add.append(new_kv)
        for k, v in private_now_public_config.items():
            if k not in public_config_keys:
                will_delete.append(v)
        self.clear_cache()
        data = []
        for i in will_add:
            data.append(i.to_api_value("add"))
        for i in will_delete:
            data.append(i.to_api_value("delete"))
        for i in will_update:
            data.append(i.to_api_value("update"))
        self.admin.api.change_key(
            self.group_id,
            self.group_name,
            data,
            is_sync=True,
            common_version_id=latest_version_id,
        )
        return will_add, will_delete, will_update

    @property
    def configs(self) -> Dict[str, KeyValue]:
        if not self.is_kv:
            raise RainbowException("不是k-v型group")
        if self._cache is None:
            self._cache = {i.key: i for i in self.get_configs()}
        return self._cache

    def add_config(self, key_values: List[KeyValue]):
        key_values = [i.to_api_value() for i in key_values]
        self.clear_cache()
        return self.admin.api.add_kv(
            self.group_id, self.group_name, key_values, is_sync=False
        )

    def delete_config(self, *keys: Union[str, KeyValue]):
        key_values = [
            self.configs[i].to_api_value("delete")
            if isinstance(i, str)
            else i.to_api_value("delete")
            for i in keys
        ]
        self.clear_cache()
        return self.admin.api.delete_key(
            self.group_id, self.group_name, key_values, is_sync=False
        )

    def update_config(self, key_values: List[KeyValue]):
        self.clear_cache()
        key_values = [i.to_api_value("update") for i in key_values]
        self.admin.api.update_key(
            self.group_id, self.group_name, key_values, is_sync=False
        )

    def get_config(self, key):
        return self.configs[key]

    def relate_to_tpl(self, tpl_name, enable_extra_file=True):
        """给分组关联模板包

        :param  tpl_name: 模板包名
        :param  enable_extra_file: <暂未使用>
        """
        return self.admin.api.group_relate_to_tpl(
            self.group_name,
            tpl_name,
            self.admin.env,
            enable_extra_file=enable_extra_file
        )

    def related_tpl(self) -> Template:
        """查看分组关联的模板包"""
        return self.admin.api.group_related_tpl(self.group_name, self.admin.env)['data']

    def preview_tpl(self, tpl_version, file_name=""):
        """
        预览模板文件渲染结果

        :param  tpl_version: 模板版本名
        :param  file_name: 仅预览指定文件
        """
        return self.admin.api.group_preview_tpl(self.admin.env, self.group_name, tpl_version, file_name)

    def query_deploy_info(self):
        return FileDeployInfo(
            **self.admin.api.query_file_deploy_info(self.group_name, self.admin.env)
        )

    def set_deploy_info(self, info: FileDeployInfo):
        return self.set_group_dir_and_shell(
            info.path,
            info.before_shell,
            info.after_shell,
            info.client_shell,
            info.client_switch,
            executor=info.executor
        )

    def fix_template_group_deploy(self, path="/tmp"):
        """初始化模板化分组的「文件下发」信息，用于修复问题"""
        return self.admin.api.change_config_module(self.group_id, path)

    def set_group_dir_and_shell(
        self,
        path: str,
        before_shell: str = "",
        after_shell: str = "",
        client_shell: str = "",
        client_switch: bool = False,
        executor: str = "",
    ):
        """设置文件目录和前后置命令

        :param path: 文件下载临时目录
        :param before_shell: 前置命令
        :param after_shell: 后置命令
        :param client_shell: 抓取客户端标识的 shell 语句
        :param client_switch: 是否开启抓取客户端标识
        :param executor: 执行前后置命令的用户名
        :return:
        """
        self.clear_cache()
        return self.admin.api.set_file_dir_and_cmd(
            self.group_name,
            path,
            before_shell,
            after_shell,
            client_shell,
            client_switch,
            self.admin.env,
            executor=executor
        )

    def __setitem__(
        self, key: str, value: Union[KeyValue, str, dict, list, int, float]
    ):
        if isinstance(value, KeyValue):
            if key in self.configs:
                self.update_config([value])
            else:
                self.add_config([value])
        else:
            if key in self.configs:
                kv = self.configs[key]
                kv.value = value
                # value_type?
                self.update_config([kv])
            else:
                self.add_config([KeyValue(key, value, group=self)])

    def __delitem__(self, key):
        self.delete_config(key)

    def __getitem__(self, item):
        return self.configs[item].value

    def __contains__(self, item):
        return item in self.configs
